-- =========================================================================
-- ESCO MIGRATION — PHASE 1: FOUNDATION
-- =========================================================================
--
-- АВТОГЕНЕРОВАНО tools/generate-esco-phase1.py — НЕ редагувати вручну.
-- Якщо треба виправити рядок — редагуй xlsx у PerenosTablu/ і перезапусти
-- скрипт, або ALTER/UPDATE окремим файлом поверх.
--
-- Переносимо до public.<table> з tenant_id='esco' ~53 рядків:
--   system_settings             25 рядків
--   app_content                  7 рядків
--   distribution_template        6 рядків
--   notifications                6 рядків
--   clients_directory            3 рядків
--   staff                        4 рядків
--   owner_account                2 рядків
--
-- Ідемпотентно: ON CONFLICT (tenant_id, <legacy_id>) DO NOTHING. Повторний
-- запуск нічого не дублює.
-- =========================================================================

BEGIN;

-- ── 1. Додаткові колонки на owner_account (Phase 1 рішення Q3=а) ────────
ALTER TABLE public.owner_account ADD COLUMN IF NOT EXISTS legacy_id text;
ALTER TABLE public.owner_account ADD COLUMN IF NOT EXISTS access_scope text;
ALTER TABLE public.owner_account ADD COLUMN IF NOT EXISTS notes text;

-- ── 2. UNIQUE індекси — обовʼязкові для ON CONFLICT у INSERT'ах нижче ──
CREATE UNIQUE INDEX IF NOT EXISTS system_settings_tenant_sid_uidx ON public.system_settings (tenant_id, setting_id);
CREATE UNIQUE INDEX IF NOT EXISTS app_content_tenant_cid_uidx ON public.app_content (tenant_id, content_id);
CREATE UNIQUE INDEX IF NOT EXISTS distribution_template_tenant_tid_uidx ON public.distribution_template (tenant_id, tmpl_id);
CREATE UNIQUE INDEX IF NOT EXISTS notifications_tenant_nid_uidx ON public.notifications (tenant_id, notif_id);
CREATE UNIQUE INDEX IF NOT EXISTS clients_directory_tenant_cid_uidx ON public.clients_directory (tenant_id, cli_id);
CREATE UNIQUE INDEX IF NOT EXISTS staff_tenant_sid_uidx ON public.staff (tenant_id, staff_id);
CREATE UNIQUE INDEX IF NOT EXISTS owner_account_tenant_login_uidx ON public.owner_account (tenant_id, login);

-- ── system_settings (25 рядків) ─────────────────────────────────────

-- ── app_content (7 рядків) ─────────────────────────────────────

-- ── distribution_template (6 рядків) ─────────────────────────────────────

-- ── notifications (5 рядків) ─────────────────────────────────────

-- ── clients_directory (3 рядків) ─────────────────────────────────────

-- ── staff (5 рядків) ─────────────────────────────────────
UPDATE public.staff SET role='owner', notes=concat_ws('; ', notes, 'Власник USR-OWN-002 (primary — у owner_account); Доступ: Всі таблиці'), updated_at=now() WHERE tenant_id='esco' AND lower(login)='vocet1987@gmail.com';

-- ── owner_account (1 рядків) ─────────────────────────────────────

COMMIT;

-- Оновити кеш PostgREST.
NOTIFY pgrst, 'reload schema';